var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"빠르게 와주신 덕분에 항구를 우선 확보할 수 있었습니다.","JPN":"迅速に来ていただいたおかげで、港を確保できました。","ENG":"Thanks to your swift arrival, we secured the harbor first.","TWN":"多虧你們迅速抵達，我們才能優先確保港口。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"선뜻 지원을 결정해 주신 것에 로터스 관리국을 대표해 깊은 감사를 드립니다.","JPN":"快く支援を出していただいたこと、ロータス管理局を代表して心から感謝いたします。","ENG":"On behalf of the Lotus Administration, thank you for committing to support us so promptly.","TWN":"我代表洛德斯管理局，向你們願意立即伸出援手深表感謝。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"알파트릭스 이노베이션만으로는 저 군세를 전부 막아낼 수 없었을 겁니다.","JPN":"アルファトリックス・イノベーションだけではあの軍勢を防ぎきれなかったでしょう。","ENG":"Alphatrix Innovation alone couldn't have held off that many.","TWN":"光靠阿爾法崔克斯改革，不可能擋下那波軍勢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"사전에 ARC-EA2에서 전선을 구축해 두었던 분들이 아니었다면 불가능한 일이겠죠.","JPN":"事前にARC-EA2で前線を築いてくれていた方々のおかげです。","ENG":"Without those who had already set up a line here in ARC-EA2, this would have been impossible.","TWN":"若不是事前就在ARC-EA2佈下戰線的那些人，根本不可能成就這一切。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그리고 저희한테 맡기실 또 다른 임무가 있다고 들었는데요.","JPN":"ところで、私たちに任せたい任務が他にもあると聞きましたが。","ENG":"I also heard you had another assignment for us.","TWN":"聽說您還有其他任務要交給我們。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"상황이 상황이니만큼 곧장 일을 진행하는 게 좋을 것 같습니다.","JPN":"こんな状況ですし、すぐに行動に移したほうがよいかと。","ENG":"Given the situation, we should move on it right away.","TWN":"現在情況緊急，最好立刻開始行動。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"의욕이 넘치는군요. 좋습니다.","JPN":"やる気満々ですね。分かりました。","ENG":"I like the enthusiasm. All right.","TWN":"幹勁十足，很好。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그럼 다음 목표에 대해 말씀드리도록 하겠습니다.","JPN":"では、次の目標について説明します。","ENG":"I will brief you on the next objective.","TWN":"那我就來說明下個目標。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"항구를 확보, 방위선을 구축해 시민들의 대피 경로를 지킨 것은 희소식입니다만,","JPN":"港を確保、防衛線を築き市民の避難経路を守れたというのは朗報でしたが。","ENG":"Securing the harbor and forming a defense line to keep evacuation routes open is good news,","TWN":"雖然你們確保港口、建立防線並守住市民的撤離路線是個好消息，"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아직 저희가 확보해야 할 구역이 하나 더 있습니다.","JPN":"もう一つ、確保しておくべき区域が残っています。","ENG":"but there is one more area we must secure.","TWN":"但我們還有一個區域必須拿下。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"바로 이터니움 보관소죠.","JPN":"つまるところ、エタニウム保管所です。","ENG":"The Eternium depot.","TWN":"就是永恆之金保管所。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"CSE 레벨이 계속해서 상승하는 한편, 이터니움 보관소를 그대로 내버려 두었다간 무슨 일이 벌어질지 모릅니다.","JPN":"CSEレベルが上昇し続けている今、エタニウム保管所を放置すれば何が起こるか分かりません。","ENG":"With CSE levels still climbing, leaving the depot unattended could have dire consequences.","TWN":"在CSE等級持續上升的情況下如果放著永恆之金保管所不管，誰也不知道會發生什麼事。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"아마 위험한 녀석이 이터니움을 매개로 현실 세계에 부상할 수도 있겠군요.","JPN":"危険なやつがエタニウムを媒介にして現実世界へ浮上するかもしれませんね。","ENG":"Something nasty could ascend into the Normalside using Eternium as a catalyst.","TWN":"說不定會有危險的傢伙以永恆之金為媒介浮上現實世界。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"맞습니다. 그렇기 때문에 반드시 이터니움 보관소를 확보해야 하죠.","JPN":"その通りです。ですから必ずエタニウム保管所を確保しなければなりません。","ENG":"Exactly. Which is why we must secure the depot.","TWN":"沒錯，所以我們務必要確保保管所的安全。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"게다가… 마왕의 강림을 막는 데 필요한 장치인 선로전환기의 가동에 많은 양의 이터니움이 필요합니다.","JPN":"それに……魔王の降臨を食い止めるための装置、線路転換器の稼働には大量のエタニウムが必要なのです。","ENG":"Also, the Track Switcher that blocks a Demon Lord's descent will require a large amount of Eternium.","TWN":"更何況……啟動阻止魔王降臨所需裝置的線路轉換器也需要大量永恆之金。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"일석이조를 노리는 셈이네요.","JPN":"一石二鳥ですね。","ENG":"Two birds with one stone.","TWN":"可以說是一舉兩得。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"거기에 보관소까지 방위선 구축을 마친다면 어느 정도 침식체를 억제할 수도 있을 테고요.","JPN":"保管所も防衛線に含ませることができれば、ある程度侵食体を抑制できるでしょうし。","ENG":"And if we extend the defense line to the depot, we can further suppress the C.O.s.","TWN":"如果在保管所也完成構築防線，多少能抑制侵蝕體的數量。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"네. 보관소는 그곳에서 멀지 않은 곳에 지어져 있습니다.","JPN":"はい。保管所は防衛線からそう遠くない場所にあります。","ENG":"Yes. The depot is not far from there.","TWN":"對，保管所就在不遠處。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"항구에서 다섯 블록 정도 가면 되는 거리죠.","JPN":"港から5ブロックほどの距離です。","ENG":"About five blocks from the harbor.","TWN":"大概距離港口五個街區的距離。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"항구로 몰려든 침식체의 숫자로 볼 때… 보관소까지 이동하는 것도 쉽지 않을 것 같은데요?","JPN":"港を襲ってきた侵食体の数からして……保管所まで移動するのも簡単にはいかなそうですね。","ENG":"Judging by the number of C.O.s swarming the harbor... getting to the depot won't be easy.","TWN":"從港口那邊湧入的侵蝕體數量來看…… 想走到保管所應該也不簡單吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"어쩌면… 보관소도 이미 점령당했을 가능성도 높고요.","JPN":"運が悪ければ……そこがすでに占拠されている可能性もあります。","ENG":"There is also a high possibility that... it may already be occupied.","TWN":"說不定……保管所已經被占領的可能性也很高。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"전 의미 없는 개죽음은 지양하는 주의라서, 지원이 필요할 것 같습니다만?","JPN":"私は無駄死には遠慮したい主義なので、支援が必要かと思いますが。","ENG":"I'm not into pointless deaths, so we will need support.","TWN":"我不做無謂的犧牲，所以恐怕需要支援。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"……죄송하지만 더 이상의 지원은 힘들지도 모릅니다.","JPN":"……すみませんが、これ以上の支援は難しいかもしれません。","ENG":"...I am sorry, but additional support may not be possible.","TWN":"……很抱歉，我們恐怕無法再提供更多支援了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아시겠지만, 로터스는 직할 도시 주변을 재건 도시들이 둘러싼 일종의 도시 집합체입니다.","JPN":"ご存知の通り、ロータスは直轄都市の周りを再建都市が囲み、都市集合体を形成しています。","ENG":"As you know, Lotus is a cluster of Reconstruction Cities surrounding the Direct Control City.","TWN":"如您所知，洛德斯是由直轄城市與周圍的重建城市組成的城市集合體。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"직할 도시 근처를 벗어나는 순간 이어지는 끝없는 사막과 침식 지대 때문에 도저히 사람이 살 수 없기 때문이죠.","JPN":"直轄都市周辺を除けば砂漠と侵食地帯が果てしなく続いていて、とても人の住める環境ではないからです。","ENG":"The moment one leaves the core city, what follows is an endless desert and Corrupted Zones, making habitation impossible.","TWN":"一旦離開直轄城市附近，就是無盡的沙漠與侵蝕地帶，根本無法生存。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당신들이 사수하고 있는 도시 말고도 여러 재건 도시가 대균열의 여파로 위기에 처한 상황입니다.","JPN":"皆さんが死守している都市の他にも、幾つもの再建都市が大亀裂の影響で危機に陥っています。","ENG":"Several other Reconstruction Cities are in crisis from the Grand Dimension Crevice's aftershocks.","TWN":"除了你們死守的城市之外，多個重建城市也因大峽谷的餘波而陷入危機。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"최대한 희생을 줄이기 위해 대균열에 가까운 도시들부터 대피를 서두르고 있지만…….","JPN":"犠牲を最低限に抑えるために、大亀裂に近い都市から避難を急いでいますが……","ENG":"To minimize casualties, we are evacuating cities closest to the Grand Dimension Crevice first, however...","TWN":"我們正盡可能從靠近大峽谷的城市開始撤離，以減少犧牲……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"결국 사람이 모자란다는 소리군요.","JPN":"つまり、人手が足りないということですね。","ENG":"So you are short on people.","TWN":"總之就是說人手不足嘛。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"좋아요. 과거 경험을 좀 살려서 어떻게든 해보죠.","JPN":"分かりました。過去の経験を活かして、なんとかしてみます。","ENG":"Fine. I'll dust off some past experience and make it work.","TWN":"好吧，那就靠過往的經驗想辦法處理吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"과거 경험이라면……?","JPN":"過去の経験、といいますと……？","ENG":"Past experience...?","TWN":"過往經驗是……？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"호위, 암살, 정적 제거, 부비트랩 설치, 건물 폭파 공작, 게릴라…….","JPN":"護衛、暗殺、政敵の排除、地雷の設置、建物爆破、ゲリラ……","ENG":"Escort, assassination, removing rivals, laying booby traps, building demolitions, guerrilla ops...","TWN":"護衛、暗殺、清除政敵、設置陷阱、爆破建築、游擊戰……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L48_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그만해도 됩니다.","JPN":"もう結構です。","ENG":"You can stop.","TWN":"我明白了，不用說了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"역시 그 복장의 문양… 낯이 익다 했더니 거미의 문양이군요.","JPN":"やはりその服の模様……見覚えがあると思いましたが、クモの模様だったんですね。","ENG":"That mark on your outfit... I knew that spider emblem looked familiar.","TWN":"果然你衣服上的圖樣……我就覺得很眼熟，是蜘蛛紋吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전부 스캐빈저에게 죽거나 투항했던 것으로 기억합니다만.","JPN":"構成員のすべてがスカベンジャーに殺されたか、投降したと記憶していますが。","ENG":"I recall the rest of them were either killed by or surrendered to Scavengers.","TWN":"我印象中那些人不是被清道夫殺了就是投降了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"저를 그런 패배자들이랑 같은 선상에 두지 마세요.","JPN":"そんな負け犬たちと同じだと思わないでください。","ENG":"Don't lump me in with losers like that.","TWN":"別把我跟那些失敗者混為一談。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"……약했기 때문에 잡아먹힌 것뿐.","JPN":"……彼らは弱かったから食われただけ。","ENG":"...They got eaten because they were weak. Simple as that.","TWN":"……因為他們太弱才會被抓走吃掉。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"아무튼 저희는 그럼 보관소가 위치한 곳으로 출발하겠습니다.","JPN":"とにかく、私たちは保管所の方へ向かいます。","ENG":"Anyway, we will head for the depot now.","TWN":"總之，我們這就前往保管所所在之處。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"무운을 빕니다, 김초원 씨.","JPN":"武運を祈ります、スズキ・ナオさん。","ENG":"Good luck, Miss Kim Chowon.","TWN":"祝你們好運，金初源小姐。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"김 씨라고 불러도 돼요.","JPN":"スズキでいいですよ。","ENG":"Just call me Kim.","TWN":"叫我金小姐就好。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"로터스에선 그 호칭이 훨씬 편하니까.","JPN":"ロータスではそちらの方が聞き慣れていますから。","ENG":"I find that name easier in Lotus.","TWN":"在洛德斯這樣叫我比較方便。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};